head.script:
scwin.g_sCurrDate = "";
scwin.tnxMm = "";
scwin.clntNo2 = "";
scwin.ModeState = "false";
scwin.upPartCd = "";

scwin.onpageload = function() {
    scwin.g_sCurrDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    ds_search.set("osideClsCd", "F");
};

scwin.onUdcCompleted = function() {
    udc_Dt.setInitDate(scwin.g_sCurrDate.substring(0, 6) + "01", scwin.g_sCurrDate);
    ds_fmsAPUnitPriceQueryConditon.set("postDt", scwin.g_sCurrDate.substring(0, 6));
    ed_tnxMm.setValue(scwin.g_sCurrDate.substring(0, 6));
    lc_commClsCd.setSelectedIndex(0);
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.f_Retrieve = async function() {
    if (!(await $c.gus.cfValidate([ica_stDt, ica_endDt]))) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(ica_stDt.getValue(), ica_endDt.getValue(), false)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return false;
    }

    await $c.sbm.execute(sbm_search);

    $c.gus.cfDisableBtn([btn_save]);
};

scwin.sbm_search_submitdone = async function(e) {
    gr_fmsInterface.refresh();
};

scwin.sbm_search_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_Create = function() {
    scwin.ModeState = "insOnLoad";
    ds_fmsInterface.insertRow(ds_fmsInterface.getRowCount());
    $c.gus.cfEnableKeyData();
    ds_fmsInterface.setCellData(ds_fmsInterface.getRowCount() - 1, "osideClsCd", "F");
    gr_fmsInterface.setReadOnly("grid", true);
};

scwin.f_Save = async function() {
    let selpchClsCd = "";

    if (ds_fmsInterface.getUpdatedIndex().length == 0) {
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    for (let row = 0; row < ds_fmsInterface.getRowCount(); row++) {
        let rowStatus = ds_fmsInterface.getRowStatus(row);
        if (rowStatus == "C" || rowStatus == "U") {
            selpchClsCd = ds_fmsInterface.getCellData(row, "selpchClsCd");
            if (selpchClsCd == "1") {
                ds_fmsInterface.setCellData(row, "slipKndCd", "H24");
                ds_fmsInterface.setCellData(row, "acctCd", "");
            } else if (selpchClsCd == "2") {
                ds_fmsInterface.setCellData(row, "slipKndCd", "H25");
                ds_fmsInterface.setCellData(row, "acctCd", "");
            }
        }
    }

    let chkValid = await $c.gus.cfValidate([gr_fmsInterface]);
    if (chkValid) {
        let chk = await $c.win.confirm(MSG_CM_CRM_001);
        if (chk == true) {
            await $c.sbm.execute(sbm_slipKnd);
        }
    }
};

scwin.sbm_slipKnd_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    $c.gus.cfDisableKeyData();
    $c.gus.cfDisableBtn([btn_save]);
    scwin.ModeState = "false";
    gr_fmsInterface.refresh();
};

scwin.sbm_slipKnd_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_Check = function() {
    if (!$c.gus.cfValidateGrid(gr_fmsInterface)) {
        return false;
    }
    return true;
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList = new Array();
    let pWhere;
    switch (disGubun) {
        case 1:
            rtnList = $c.gus.cfCommonPopUp("retrieveClntEmpNoList", pCode, pName, "T", null, null, null, null, null, null, null, null, null);
            $c.gus.cfSetReturnValue(rtnList, ed_clntNoCond, txt_clntNmCond);
            break;
        case 2:
            rtnList = $c.gus.cfCommonPopUp("retrieveClntEmpNoList", pCode, "", "T", null, null, null, null, null, null, null, null, null);
            if (rtnList != null && rtnList[0] != "N/A") {
                let curRow = ds_fmsInterface.getRowPosition();
                ds_fmsInterface.setCellData(curRow, "clntNo", rtnList[0]);
                ds_fmsInterface.setCellData(curRow, "clntNm", rtnList[1]);
            }
            break;
        case 3:
            rtnList = $c.gus.cfCommonPopUp("retrieveAcctDeptCdInfo", pCode, "", "T", null, null, null, null, null, null, null, null, null);
            if (rtnList != null && rtnList[0] != "N/A") {
                let curRow = ds_fmsInterface.getRowPosition();
                ds_fmsInterface.setCellData(curRow, "acctDeptCd", rtnList[0]);
                ds_fmsInterface.setCellData(curRow, "acctDeptNm", rtnList[1]);
            }
            break;
        case 4:
            rtnList = $c.gus.cfCommonPopUp("retrieveClntEmpNoList", pCode, pName, "T", null, null, null, null, null, null, null, null, null);
            $c.gus.cfSetReturnValue(rtnList, ed_clntNo2, txt_clntNm2);
            break;
    }
    return;
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    } else {
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
    }
};

scwin.f_Excel = async function() {
    let chk = await $c.win.confirm("Excel로 다운로드 하시겠습니까?");
    if (chk) {
        $c.data.downloadGridViewExcel(gr_fmsInterface, {"fileName": "정비직판매출입.xlsx", "sheetName": "정비직판매출입"});
    }
};

scwin.f_Excel2 = async function() {
    let chk = await $c.win.confirm("Excel 양식을 다운로드 하시겠습니까?");
    if (chk) {
        gr_fmsInterface.setColumnVisible("acctCd", false);
        gr_fmsInterface.setColumnVisible("acctDeptCd", false);
        gr_fmsInterface.setColumnVisible("acctDeptNm", false);
        gr_fmsInterface.setColumnVisible("upr", false);
        gr_fmsInterface.setColumnVisible("amt", false);
        gr_fmsInterface.setColumnVisible("vat", false);
        gr_fmsInterface.setColumnVisible("slipNo", false);
        gr_fmsInterface.setColumnVisible("sumAmt", false);
        gr_fmsInterface.setColumnVisible("clntNo", true);
        gr_fmsInterface.setColumnVisible("stockSetlYn", false);

        $c.data.downloadGridViewExcel(gr_fmsInterface, {"fileName": "정비직판매출입.xlsx", "sheetName": "정비직판매출입"});

        gr_fmsInterface.setColumnVisible("commClsCd", true);
        gr_fmsInterface.setColumnVisible("upr", true);
        gr_fmsInterface.setColumnVisible("amt", true);
        gr_fmsInterface.setColumnVisible("vat", true);
        gr_fmsInterface.setColumnVisible("slipNo", true);
        gr_fmsInterface.setColumnVisible("sumAmt", true);
        gr_fmsInterface.setColumnVisible("clntNo", false);

        gr_fmsInterface.refresh();
    }
};

scwin.f_grdHeiht = function(size) {
    let strHeight = gr_fmsInterface.style.height;
    let intHeight = parseInt(strHeight.replace("px", ""));
    intHeight = intHeight + size;
    if (intHeight > 0) {
        gr_fmsInterface.style.height = intHeight + "px";
    }
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tb_retrieve, null);
};

scwin.f_AddRow = function() {
    if (!scwin.f_Check()) {
        return;
    }
    ds_fmsInterface.insertRow(ds_fmsInterface.getRowCount());
    let curRow = ds_fmsInterface.getRowPosition();
    ds_fmsInterface.setCellData(curRow, "postDt", new Date().format("YYYYMMDD"));
    ds_fmsInterface.setCellData(curRow, "qty", 0);
    ds_fmsInterface.setCellData(curRow, "upr", 0);
    ds_fmsInterface.setCellData(curRow, "amt", 0);
    ds_fmsInterface.setCellData(curRow, "vat", 0);
    ds_fmsInterface.setCellData(curRow, "rmk", "");
    ds_fmsInterface.setCellData(curRow, "slipNo", "");
    ds_fmsInterface.setCellData(curRow, "sumAmt", 0);
    ds_fmsInterface.setCellData(curRow, "acctCd", "");
    ds_fmsInterface.setCellData(curRow, "acctDeptCd", "");
    ds_fmsInterface.setCellData(curRow, "osideClsCd", "F");
};

scwin.f_DelRow = async function() {
    if (ds_fmsInterface.getRowCount() == 0) {
        await $c.win.alert("삭제할 데이타가 없습니다");
        return;
    }
    let curRow = ds_fmsInterface.getRowPosition();
    let slipNo = ds_fmsInterface.getCellData(curRow, "slipNo");
    if (slipNo != "") {
        await $c.win.alert((curRow + 1) + "행은 이미 전표를 생성하였으므로 삭제하실 수 없습니다.");
        return;
    }
    ds_fmsInterface.removeRow(curRow);
};

scwin.f_DelRowAll = async function() {
    if (ds_fmsInterface.getRowCount() == 0) {
        await $c.win.alert("삭제할 데이타가 없습니다");
        return;
    }

    let slipNo = "";
    for (let x = 0; x < ds_fmsInterface.getRowCount(); x++) {
        slipNo = ds_fmsInterface.getCellData(x, "slipNo");
        if (slipNo != "") {
            await $c.win.alert((x + 1) + "행은 이미 전표를 생성하였으므로 삭제하실 수 없습니다.");
            return;
        }
        ds_fmsInterface.removeRow(x);
    }
};

scwin.f_CalcAmount = async function() {
    let postDtVal = ds_fmsAPUnitPriceQueryConditon.get("postDt");
    if ($c.gus.cfValidateValue(postDtVal, "date=YYYYMM") && postDtVal.trim() != "") {
        let chk = await $c.win.confirm(MSG_CM_CRM_001);
        if (chk == true) {
            await $c.sbm.execute(sbm_calcAmount);
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_018, ["기준년월"]);
    }
};

scwin.sbm_calcAmount_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_Retrieve();
};

scwin.sbm_calcAmount_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_certiPrint = async function() {
    $c.gus.OZStartBatch();

    let tnxMmVal = ed_tnxMm.getValue();
    let ctrlNo = ed_clntNo2.getValue();
    let constSiteVal = lc_constSite.getValue();
    let curDt = ed_tnxMm.getValue().substring(4, 6);

    let chkValid = await $c.gus.cfValidate([ed_tnxMm, ed_clntNo2, lc_constSite]);
    if (!chkValid) {
        return;
    }

    if (constSiteVal.trim() == "") {
        await $c.win.alert("공사현장은 필수 입력항목입니다.");
        lc_constSite.setFocus();
        return;
    }

    let odiParam = new $c.gus.ODIParam("eq_630_01_04b");

    odiParam.add("tnxMm", tnxMmVal);
    odiParam.add("ctrlNo", ctrlNo);
    odiParam.add("constSite", constSiteVal);
    odiParam.add("curDt", curDt);

    let formParam = new $c.gus.FormParam();
    let viewerParam = new $c.gus.ViewerParam();
    viewerParam.add("viewer.zoom", "100");
    viewerParam.add("print.mode", "silent");
    viewerParam.add("print.copies", 1);
    viewerParam.add("viewer.useprogressbar", "false");
    $c.gus.cfOZReport("chb_printCheck", "chb_previewCheck", "/ps/eq/fmsmgnt/eq_630_01_04b.ozr", odiParam, viewerParam, formParam);

    $c.gus.OZExecuteBatch();
};

scwin.f_getConstSite = function() {
    // TODO: co_ds_combo.DataID 동적 로딩은 WebSquare submission으로 대체 필요
    let url = "/cm.zz.RetrieveComboCMD.do?sysCd=PsCommonEBC&queryId=retrieveConstSite&param1=" + ed_tnxMm.getValue() + "&param2=" + ed_clntNo2.getValue();
    // TODO: 공사현장 콤보 데이터 동적 로딩 구현 필요
};

scwin.btn_save_onclick = function(e) {
    scwin.f_Save();
};

scwin.btn_certiPrint_onclick = function(e) {
    scwin.f_certiPrint();
};

scwin.btn_calcAmount_onclick = function(e) {
    scwin.f_CalcAmount();
};

scwin.btn_trigger3_onclick = function(e) {
    scwin.f_DelRowAll();
};

scwin.btn_trigger4_onclick = function(e) {
    scwin.f_Excel2();
};

scwin.ds_fmsInterface_onloadcompleted = async function(e) {
    let rowCnt = ds_fmsInterface.getRowCount();
    $c.gus.cfShowTotalRows(totalRows, rowCnt);
    $c.gus.cfDisableBtn([btn_save]);
    if (rowCnt == 0) {
        if ($c.gus.cfCheckCreateFlag() == true) {
            $c.gus.cfTurnCreateFlag(false);
        } else {
            await $c.win.alert("조회된 데이터가 없습니다.");
        }
    }
};

scwin.ds_fmsInterface_onrowpositionchange = function(rowIndex) {
    let row = rowIndex;
    if (row < 0) return;
    let RowStatus = ds_fmsInterface.getRowStatus(row);

    gr_fmsInterface.setColumnReadOnly("postDt", true);
    gr_fmsInterface.setColumnReadOnly("clntNm", true);
    gr_fmsInterface.setColumnReadOnly("clntNo", true);
    gr_fmsInterface.setColumnReadOnly("selpchClsCd", true);
    gr_fmsInterface.setColumnReadOnly("commClsCd", false);
    gr_fmsInterface.setColumnReadOnly("evidClsCd", true);
    gr_fmsInterface.setColumnReadOnly("qty", true);
    gr_fmsInterface.setColumnReadOnly("amt", true);
    gr_fmsInterface.setColumnReadOnly("vat", true);
    gr_fmsInterface.setColumnReadOnly("rmk", true);
    gr_fmsInterface.setColumnReadOnly("slipNo", true);
    gr_fmsInterface.setColumnReadOnly("sumAmt", true);
    gr_fmsInterface.setColumnReadOnly("acctCd", true);
    gr_fmsInterface.setColumnReadOnly("acctDeptCd", true);
    gr_fmsInterface.setColumnReadOnly("acctDeptNm", true);
    gr_fmsInterface.setColumnReadOnly("slipKndCd", true);
    gr_fmsInterface.setColumnReadOnly("osideClsCd", true);
    gr_fmsInterface.setColumnReadOnly("upr", true);
    gr_fmsInterface.setColumnReadOnly("constSite", true);
    gr_fmsInterface.setColumnReadOnly("rcptClnt", true);
    gr_fmsInterface.setColumnReadOnly("pcostAmt", true);
    gr_fmsInterface.setColumnReadOnly("stockSetlYn", true);

    let slipNoVal = ds_fmsInterface.getCellData(row, "slipNo");
    if (slipNoVal == null || slipNoVal.trim() == "") {
        if (RowStatus == "R" || RowStatus == "U") {
            gr_fmsInterface.setColumnReadOnly("evidClsCd", false);
            gr_fmsInterface.setColumnReadOnly("qty", false);
            gr_fmsInterface.setColumnReadOnly("constSite", false);
            gr_fmsInterface.setColumnReadOnly("rcptClnt", false);
            gr_fmsInterface.setColumnReadOnly("rmk", false);
            gr_fmsInterface.setColumnReadOnly("pcostAmt", false);
            gr_fmsInterface.setColumnReadOnly("stockSetlYn", false);
        } else if (RowStatus == "C") {
            gr_fmsInterface.setColumnReadOnly("postDt", false);
            gr_fmsInterface.setColumnReadOnly("clntNo", false);
            gr_fmsInterface.setColumnReadOnly("clntNm", false);
            gr_fmsInterface.setColumnReadOnly("selpchClsCd", false);
            gr_fmsInterface.setColumnReadOnly("evidClsCd", false);
            gr_fmsInterface.setColumnReadOnly("qty", false);
            gr_fmsInterface.setColumnReadOnly("constSite", false);
            gr_fmsInterface.setColumnReadOnly("rcptClnt", false);
            gr_fmsInterface.setColumnReadOnly("rmk", false);
            gr_fmsInterface.setColumnReadOnly("pcostAmt", false);
            gr_fmsInterface.setColumnReadOnly("stockSetlYn", false);
        }
    }
};

scwin.gr_fmsInterface_oneditend = function(rowIndex, columnId, oldValue, newValue) {
    let row = rowIndex;
    let rtnList;
    if (columnId == "clntNm") {
        rtnList = $c.gus.cfCommonPopUp("retrieveClntEmpNoList", ds_fmsInterface.getCellData(row, "clntNo"), ds_fmsInterface.getCellData(row, "clntNm"), "T", null, null, null, null, null, null, null, null, null);
        if (rtnList != null && rtnList[0] != "N/A") {
            ds_fmsInterface.setCellData(row, "clntNo", rtnList[0]);
            ds_fmsInterface.setCellData(row, "clntNm", rtnList[1]);
        }
    } else if (columnId == "acctDeptCd") {
        rtnList = $c.gus.cfCommonPopUp("retrieveAcctDeptCdInfo", ds_fmsInterface.getCellData(row, "acctDeptCd"), "", "T", null, null, null, null, null, null, null, null, null);
        if (rtnList != null && rtnList[0] != "N/A") {
            ds_fmsInterface.setCellData(row, "acctDeptCd", rtnList[0]);
            ds_fmsInterface.setCellData(row, "acctDeptNm", rtnList[1]);
        }
    } else if (columnId == "acctDeptCm") {
        rtnList = $c.gus.cfCommonPopUp("retrieveAcctDeptCdInfo", "", ds_fmsInterface.getCellData(row, "acctDeptNm"), "T", null, null, null, null, null, null, null, null, null);
        if (rtnList != null && rtnList[0] != "N/A") {
            ds_fmsInterface.setCellData(row, "acctDeptCd", rtnList[0]);
            ds_fmsInterface.setCellData(row, "acctDeptNm", rtnList[1]);
        }
    }
    return true;
};

scwin.ed_clntNoCond_onblur = function(e) {
    scwin.f_openCommonPopUp(1, ed_clntNoCond.getValue(), txt_clntNmCond.getValue(), "F", "F");
};

scwin.gr_fmsInterface_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    let row = rowIndex;
    let rtnList = new Array();
    if (columnId == "postDt") {
        // TODO: cfOpenCalendar 그리드 내 달력 팝업 — inputType="calendar"로 대체됨
    } else if (columnId == "clntNm") {
        rtnList = $c.gus.cfCommonPopUp("retrieveClntEmpNoList", ds_fmsInterface.getCellData(row, "clntNo"), ds_fmsInterface.getCellData(row, "clntNm"), "T", null, null, null, null, null, null, null, null, null);
        if (rtnList != null && rtnList[0] != "N/A") {
            ds_fmsInterface.setCellData(row, "clntNo", rtnList[0]);
            ds_fmsInterface.setCellData(row, "clntNm", rtnList[1]);
        }
    }
    return true;
};

scwin.gr_fmsInterface_onheaderclick = function(columnIndex, columnId) {
    if (columnId == "stockSetlYn") {
        let bCheck = gr_fmsInterface.getHeaderValue(0, columnIndex);
        if (bCheck == "1") {
            for (let i = 0; i < ds_fmsInterface.getRowCount(); i++) {
                let rowStatus = ds_fmsInterface.getRowStatus(i);
                if (rowStatus == "C" || rowStatus == "U") {
                    ds_fmsInterface.setCellData(i, "stockSetlYn", "1");
                }
            }
        } else {
            for (let i = 0; i < ds_fmsInterface.getRowCount(); i++) {
                ds_fmsInterface.setCellData(i, "stockSetlYn", "0");
            }
        }
    }
};

scwin.ed_tnxMm_onfocus = function(e) {
    scwin.tnxMm = ed_tnxMm.getValue();
};

scwin.ed_tnxMm_onblur = function(e) {
    if (scwin.tnxMm != ed_tnxMm.getValue()) {
        scwin.f_getConstSite();
    }
};

scwin.ed_clntNo2_onfocus = function(e) {
    scwin.clntNo2 = ed_clntNo2.getValue();
};

scwin.ed_clntNo2_onblur = function(e) {
    scwin.f_openCommonPopUp(4, ed_clntNo2.getValue(), txt_clntNm2.getValue(), "F", "F");
    if (scwin.clntNo2 != ed_clntNo2.getValue()) {
        scwin.f_getConstSite();
    }
};

scwin.co_ds_combo_onloadcompleted = function(e) {
    lc_constSite.setSelectedIndex(0);
};
